1748     ++BBI;
1749     eraseInstruction(M);
1750     return true;
1751   }
1752 
1753   // If the size is zero, remove the memcpy.
1754   if (isZeroSize(M->getLength())) {
1755     ++BBI;
1756     eraseInstruction(M);
1757     return true;
1758   }
