1873 /// Memmove calls with overlapping src/dest buffers that come after a memset may
1874 /// be removed.
1875 bool MemCpyOptPass::isMemMoveMemSetDependency(MemMoveInst *M) {
1876   const auto &DL = M->getDataLayout();
1877   MemoryUseOrDef *MemMoveAccess = MSSA->getMemoryAccess(M);
1878   if (!MemMoveAccess)
1879     return false;
1880 
1881   // The memmove is of form memmove(x, x + A, B).
1882   MemoryLocation SourceLoc = MemoryLocation::getForSource(M);
1883   auto *MemMoveSourceOp = M->getSource();
1884   auto *Source = dyn_cast<GEPOperator>(MemMoveSourceOp);
1885   if (!Source)
1886     return false;
1887 
1888   APInt Offset(DL.getIndexTypeSizeInBits(Source->getType()), 0);
1889   LocationSize MemMoveLocSize = SourceLoc.Size;
1890   if (Source->getPointerOperand() != M->getDest() ||
1891       !MemMoveLocSize.hasValue() ||
1892       !Source->accumulateConstantOffset(DL, Offset) || Offset.isNegative()) {
1893     return false;
1894   }
1895 
1896   uint64_t MemMoveSize = MemMoveLocSize.getValue();
1897   LocationSize TotalSize =
1898       LocationSize::precise(Offset.getZExtValue() + MemMoveSize);
1899   MemoryLocation CombinedLoc(M->getDest(), TotalSize);
1900 
1901   // The first dominating clobbering MemoryAccess for the combined location
1902   // needs to be a memset.
1903   BatchAAResults BAA(*AA);
1904   MemoryAccess *FirstDef = MemMoveAccess->getDefiningAccess();
1905   auto *DestClobber = dyn_cast<MemoryDef>(
1906       MSSA->getWalker()->getClobberingMemoryAccess(FirstDef, CombinedLoc, BAA));
1907   if (!DestClobber)
1908     return false;
1909 
1910   auto *MS = dyn_cast_or_null<MemSetInst>(DestClobber->getMemoryInst());
1911   if (!MS)
1912     return false;
1913 
1914   // Memset length must be sufficiently large.
1915   auto *MemSetLength = dyn_cast<ConstantInt>(MS->getLength());
1916   if (!MemSetLength || MemSetLength->getZExtValue() < MemMoveSize)
1917     return false;
1918 
1919   // The destination buffer must have been memset'd.
1920   if (!BAA.isMustAlias(MS->getDest(), M->getDest()))
1921     return false;
1922 
1923   return true;
1924 }
